36.query:
timeseries {
  cpuUsage = avg(dt.host.cpu.usage),
    filter:{
      dt.entity.host in [
        fetch dt.entity.host
        | filter matchesValue(entity.name, $Host)
        | fields id
      ]      
    }
},
union: TRUE,
interval: 5m
| fieldsAdd cpuUsage.Median = arrayAvg(cpuUsage)
| fieldsAdd cpuUsage.AvgLowerThanMedian = arrayAvg(iCollectArray(if(cpuUsage[] < cpuUsage.Median, cpuUsage[], else: null)))
| fieldsAdd cpuUsage.AvgHigherThanMedian = arrayAvg(iCollectArray(if(cpuUsage[] > cpuUsage.Median, cpuUsage[], else: null)))
| fieldsAdd cpuUsage.PercentChange = 100 * (cpuUsage.AvgHigherThanMedian - cpuUsage.AvgLowerThanMedian) / (cpuUsage.AvgLowerThanMedian)
| fieldsAdd ForecastedCPU = cpuUsage.Median*(1 + toDouble($TrafficChangePercent)*(cpuUsage.PercentChange/toDouble(array($TrafficLoad)[3]))/100)
//| fieldsAdd ForecastedCPU = arrayMax(array(0, arrayMin(array(ForecastedCPU, 100))))
| fieldsAdd ForecastedLowTrafficCPU = cpuUsage.AvgLowerThanMedian*(1 + toDouble($TrafficChangePercent)*(cpuUsage.PercentChange/toDouble(array($TrafficLoad)[3]))/100)
//| fieldsAdd ForecastedLowTrafficCPU = arrayMax(array(1, arrayMin(array(ForecastedLowTrafficCPU, 100))))
| fieldsAdd ForecastedHighTrafficCPU = cpuUsage.AvgHigherThanMedian*(1 + toDouble($TrafficChangePercent)*(cpuUsage.PercentChange/toDouble(array($TrafficLoad)[3]))/100)
//| fieldsAdd ForecastedHighTrafficCPU = arrayMax(array(2, arrayMin(array(ForecastedHighTrafficCPU, 100))))

| fieldsAdd `Current Metric` = array("Observed Low","Observed Average","Observed High","Forecast Low","Forecast Average","Forecast High")
| expand `Current Metric`
| fieldsAdd `Metric Value` = if(`Current Metric` == "Observed Low", round(cpuUsage.AvgLowerThanMedian, decimals: 2), 
			     else: if(`Current Metric` == "Observed Average", round(cpuUsage.Median, decimals: 2),
			           else: if(`Current Metric` == "Observed High", round(cpuUsage.AvgHigherThanMedian, decimals: 2),
			           else: if(`Current Metric` == "Forecast Low", round(ForecastedLowTrafficCPU, decimals: 2),
			           else: if(`Current Metric` == "Forecast Average", round(ForecastedCPU, decimals: 2),
                                               else: round(ForecastedHighTrafficCPU, decimals: 2))))))
| fields `Current Metric`,`Metric Value`

